targets.expr:
# CPU Requested
kube_namespace_labels{
    label_product=~"$product", 
    label_project=~"$project", 
    label_environment_kind=~"$kind", 
    cluster=~"$cluster", 
    namespace=~"$namespace"
} 
* on (cluster, namespace) 
group_right(label_environment_kind, label_product, label_project, label_client) 
(
    sum by (cluster, namespace) (
        avg_over_time(
            namespace_cpu:kube_pod_container_resource_requests:sum{
                cluster=~"$cluster", 
                namespace=~"$namespace"
            }[$__range:$__interval]
        )
    ) 
    or 
    sum by (cluster, namespace) (
        kube_namespace_labels{cluster=~"$cluster", namespace=~"$namespace"}
    ) * 0
)

# RAM Requested, public cloud
kube_namespace_labels{
    label_product=~"$product", 
    label_project=~"$project", 
    label_environment_kind=~"$kind", 
    cluster=~"$cluster", 
    namespace=~"$namespace"
} 
* on (cluster, namespace) 
group_right(label_environment_kind, label_product, label_project, label_client) 
(
    sum by (cluster, namespace) (
        avg_over_time(
            namespace_memory:kube_pod_container_resource_requests_not_bare_metal:sum{
                cluster=~"$cluster", 
                namespace=~"$namespace"
            }[$__range:$__interval]
        ) / 1024^3
    )
    or 
    sum by (cluster, namespace) (
        kube_namespace_labels{cluster=~"$cluster", namespace=~"$namespace"}
    ) * 0
)

