# Storage Requested
kube_namespace_labels{
    label_product=~"$product", 
    label_project=~"$project", 
    label_environment_kind=~"$kind", 
    cluster=~"$cluster", 
    namespace=~"$namespace"
} 
* on (cluster, namespace)
group_right(label_environment_kind, label_product, label_project, label_client) 
(
    sum by (cluster, namespace) (
        avg_over_time(
            sum without (storageclass) (
                namespace_persistentvolumeclaim:kube_persistentvolumeclaim_storageclass_resource_requests_storage_bytes:sum{
                    cluster=~"$cluster", 
                    namespace=~"$namespace", 
                    storageclass!~"csi-topolvm-standard-.*"
                }
            )[$__range:$__interval]
        ) / 1024^3
    )
    or 
    sum by (cluster, namespace) (
        kube_namespace_labels{cluster=~"$cluster", namespace=~"$namespace"} * 0
    )
)

# Storage Requested, bare metal
kube_namespace_labels{
    label_project=~"$project", 
    label_product=~"$product", 
    label_environment_kind=~"$kind", 
    cluster=~"$cluster", 
    namespace=~"$namespace"
} 
* on (cluster, namespace) 
group_right(label_environment_kind, label_product, label_project, label_client) 
(
  sum by (cluster, namespace) (
    avg_over_time(
      sum without (storageclass) (
        namespace_persistentvolumeclaim:kube_persistentvolumeclaim_storageclass_resource_requests_storage_bytes:sum{
            cluster=~"$cluster", 
            namespace=~"$namespace", 
            storageclass=~"csi-topolvm-standard-.*"
        }
      )[$__range:$__interval]
    ) / 1024^3
  )
  or 
  sum by (cluster, namespace) (
      kube_namespace_labels{cluster=~"$cluster", namespace=~"$namespace"}
  ) * 0
)

# Actual CPU Usage
kube_namespace_labels{
    label_product=~"$product", 
    label_project=~"$project", 
    label_environment_kind=~"$kind", 
    cluster=~"$cluster", 
    namespace=~"$namespace"
} 
* on (cluster, namespace)
group_right(label_environment_kind, label_product, label_project, label_client) 
(
  sum by (cluster, namespace) (
    avg_over_time(
      namespace:container_cpu_usage_seconds_total:sum_irate{
          cluster=~"$cluster", 
          namespace=~"$namespace"
      }[$__range:$__interval]
    )
  )
  or 
  sum by (cluster, namespace) (
      kube_namespace_labels{cluster=~"$cluster", namespace=~"$namespace"}
  ) * 0
)

# Actual memory usage
kube_namespace_labels{
    label_product=~"$product", 
    label_project=~"$project", 
    label_environment_kind=~"$kind", 
    cluster=~"$cluster", 
    namespace=~"$namespace"
} 
* on (cluster, namespace) 
group_right(label_environment_kind, label_product, label_project, label_client) 
(
  sum by (cluster, namespace) (
    avg_over_time(
      namespace:container_memory_working_set_bytes:sum{
          cluster=~"$cluster", 
          namespace=~"$namespace"
      }[$__range:$__interval]
    ) / 1024^3
  )
  or 
  sum by (cluster, namespace) (
      kube_namespace_labels{cluster=~"$cluster", namespace=~"$namespace"}
  ) * 0
)

# Storage Requested
kube_namespace_labels{label_project=~"$project", label_product=~"$product", label_environment_kind=~"$kind", cluster="$cluster", namespace=~"$namespace"} * on (namespace) group_right(label_environment_kind, label_product, label_project, label_client) (
  avg_over_time(
    sum without (storageclass) (
      namespace_persistentvolumeclaim:kube_persistentvolumeclaim_storageclass_resource_requests_storage_bytes:sum{cluster="$cluster", namespace=~"$namespace", storageclass!~"csi-topolvm-standard-.*"}
    )[$__range:$__interval]
  ) / 1024^3
  or sum by (cluster, namespace, prometheus, prometheus_replica) (kube_namespace_labels{cluster="$cluster", namespace=~"$namespace"} * 0) # Allow to list even namespaces without PVC
)

- on (cluster, namespace, label_product, label_project, label_client, label_environment_kind)

kube_namespace_labels{label_project=~"$project", label_product=~"$product", label_environment_kind=~"$kind", cluster="$cluster", namespace=~"$namespace"} * on (namespace) group_right(label_environment_kind, label_product, label_project, label_client) (
  avg_over_time(
    sum without (storageclass) (
      namespace_persistentvolumeclaim:kube_persistentvolumeclaim_storageclass_resource_requests_storage_bytes:sum{cluster="$cluster", namespace=~"$namespace", storageclass!~"csi-topolvm-standard-.*"}
    )[$__range:$__interval]  offset 30d
  ) / 1024^3
  or sum by (cluster, namespace, prometheus, prometheus_replica) (kube_namespace_labels{cluster="$cluster", namespace=~"$namespace"} * 0) # Allow to list even namespaces without PVC
)

